using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag and
        // encodes names as UTF-8. Our legacy Java consumer reads filenames as Shift-JIS.
        // Use the ZipFile.Open overload with an explicit Shift-JIS encoding so entry
        // names are written in Shift-JIS (without the UTF-8 flag set).
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift-JIS");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

